{
  "name": "Hulpverleners van BHV land Dashboard",
  "description": "Instructeur dashboard voor het BHV spel, inclusief team management, vaardigheden afvinken, vragenlijsten en incident status.",
  "requestFramePermissions": []
}

import React, { useState } from 'react';
import { TEAMS, DOOR_POINTS, SKILLS, QUESTION_REWARDS, INCIDENT_REWARDS } from './constants';
import { TeamState, TeamColor, DoorState, Resource } from './types';
import TeamCard from './components/TeamCard';
import SkillsModal from './components/SkillsModal';
import QuestionsModal from './components/QuestionsModal';
import RewardModal from './components/RewardModal';
import Leaderboard from './components/Leaderboard';
import { Users, LayoutDashboard, Crown } from 'lucide-react';

const initialTeamState = (color: TeamColor): TeamState => ({
  color,
  active: false,
  completedSkills: [],
  answeredQuestions: [],
  incidentDone: false,
  routeLength: 2, // Default 2 points for route length
  doors: {
    basic: 2, // Default 2 points (2 basic doors)
    min30: 0,
    min60: 0
  }
});

const calculateDoorPoints = (doors: DoorState) => {
  return (doors.basic * DOOR_POINTS.basic) + 
         (doors.min30 * DOOR_POINTS.min30) + 
         (doors.min60 * DOOR_POINTS.min60);
};

const App: React.FC = () => {
  const [view, setView] = useState<'setup' | 'dashboard'>('setup');

  const [teams, setTeams] = useState<Record<TeamColor, TeamState>>({
    red: initialTeamState('red'),
    blue: initialTeamState('blue'),
    yellow: initialTeamState('yellow'),
    orange: initialTeamState('orange'),
  });

  // Modal State
  const [activeModal, setActiveModal] = useState<{ type: 'skills' | 'questions', teamColor: TeamColor } | null>(null);

  // Reward State
  const [rewardData, setRewardData] = useState<{ 
    teamColor: TeamColor; 
    resources: Resource[];
    source: string;
  } | null>(null);

  const toggleTeamActive = (color: TeamColor) => {
    setTeams(prev => ({
      ...prev,
      [color]: { ...prev[color], active: !prev[color].active }
    }));
  };

  const handleToggleSkill = (teamColor: TeamColor, skillId: string) => {
    const skill = SKILLS.find(s => s.id === skillId);

    setTeams(prev => {
      const team = prev[teamColor];
      const hasSkill = team.completedSkills.includes(skillId);

      // If we are checking the box (completing the skill), trigger reward
      if (!hasSkill && skill) {
        setRewardData({
            teamColor,
            resources: skill.rewards,
            source: skill.name
        });
      }

      return {
        ...prev,
        [teamColor]: {
          ...team,
          completedSkills: hasSkill 
            ? team.completedSkills.filter(id => id !== skillId)
            : [...team.completedSkills, skillId]
        }
      };
    });
  };

  const handleToggleQuestion = (teamColor: TeamColor, questionId: number) => {
    setTeams(prev => {
      const team = prev[teamColor];
      const hasAnswered = team.answeredQuestions.includes(questionId);

      // Trigger reward if answering for the first time
      if (!hasAnswered) {
        setRewardData({
            teamColor,
            resources: QUESTION_REWARDS,
            source: 'Vraag goed beantwoord'
        });
      }

      return {
        ...prev,
        [teamColor]: {
          ...team,
          answeredQuestions: hasAnswered
            ? team.answeredQuestions.filter(id => id !== questionId)
            : [...team.answeredQuestions, questionId]
        }
      };
    });
  };

  const handleToggleIncident = (teamColor: TeamColor) => {
    setTeams(prev => {
        const isDone = prev[teamColor].incidentDone;

        // Trigger reward if marking as done
        if (!isDone) {
            setRewardData({
                teamColor,
                resources: INCIDENT_REWARDS,
                source: 'Incident opgelost'
            });
        }

        return {
            ...prev,
            [teamColor]: { ...prev[teamColor], incidentDone: !isDone }
        };
    });
  };

  const handleUpdateRoute = (teamColor: TeamColor, val: number) => {
    setTeams(prev => ({
      ...prev,
      [teamColor]: { ...prev[teamColor], routeLength: val }
    }));
  };

  const handleUpdateDoors = (teamColor: TeamColor, type: keyof DoorState, val: number) => {
    setTeams(prev => ({
      ...prev,
      [teamColor]: { 
        ...prev[teamColor], 
        doors: {
          ...prev[teamColor].doors,
          [type]: val
        } 
      }
    }));
  };

  const activeTeamsList = (Object.values(teams) as TeamState[]).filter(t => t.active);
  const hasActiveTeams = activeTeamsList.length > 0;

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900">

      {/* Navbar */}
      <nav className="bg-white border-b border-slate-200 shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-600 p-2 rounded-lg text-white">
                <Crown size={20} />
             </div>
             <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
               Hulpverleners van BHV land
             </h1>
          </div>
          <div className="flex items-center gap-4">
            {view === 'dashboard' && (
              <button 
                onClick={() => setView('setup')}
                className="text-sm font-medium text-slate-500 hover:text-slate-800 transition-colors"
              >
                Teamconfiguratie
              </button>
            )}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

        {view === 'setup' && (
          <div className="max-w-2xl mx-auto">
            <div className="text-center mb-10">
              <h2 className="text-3xl font-bold text-slate-800 mb-3">Welke teams spelen mee?</h2>
              <p className="text-slate-500">Selecteer de groepen die vandaag meedoen aan de training.</p>
            </div>

            <div className="grid gap-4">
              {(Object.keys(TEAMS) as TeamColor[]).map((color) => {
                const config = TEAMS[color];
                const isActive = teams[color].active;
                return (
                  <button
                    key={color}
                    onClick={() => toggleTeamActive(color)}
                    className={`flex items-center justify-between p-6 rounded-xl border-2 transition-all duration-300 shadow-sm hover:shadow-md ${
                      isActive 
                        ? 'border-indigo-600 bg-white scale-[1.02]' 
                        : 'border-transparent bg-slate-200 opacity-60 hover:opacity-100'
                    }`}
                  >
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-full shadow-inner flex items-center justify-center text-white font-bold`} style={{ backgroundColor: config.hex }}>
                         {isActive && <Users size={20} className={config.textColor} />}
                      </div>
                      <span className="text-xl font-bold text-slate-800">{config.name}</span>
                    </div>
                    <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center ${isActive ? 'bg-indigo-600 border-indigo-600' : 'border-slate-400'}`}>
                      {isActive && <Users size={16} className="text-white" />}
                    </div>
                  </button>
                );
              })}
            </div>

            <button
              onClick={() => setView('dashboard')}
              disabled={!hasActiveTeams}
              className={`w-full mt-8 py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-2 transition-all ${
                hasActiveTeams 
                  ? 'bg-indigo-600 text-white hover:bg-indigo-700 translate-y-0' 
                  : 'bg-slate-300 text-slate-500 cursor-not-allowed'
              }`}
            >
              <LayoutDashboard size={24} />
              Start Dashboard
            </button>
          </div>
        )}

        {view === 'dashboard' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">

            {/* New Comprehensive Leaderboard */}
            {hasActiveTeams && (
                <Leaderboard teams={activeTeamsList} />
            )}

            {/* Team Cards Grid */}
            <div className={`grid gap-6 ${activeTeamsList.length === 1 ? 'max-w-md mx-auto' : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-4'}`}>
              {activeTeamsList.map(team => (
                <TeamCard 
                  key={team.color}
                  teamState={team}
                  onOpenSkills={() => setActiveModal({ type: 'skills', teamColor: team.color })}
                  onOpenQuestions={() => setActiveModal({ type: 'questions', teamColor: team.color })}
                  onToggleIncident={() => handleToggleIncident(team.color)}
                  onUpdateRoute={(val) => handleUpdateRoute(team.color, val)}
                  onUpdateDoors={(type, val) => handleUpdateDoors(team.color, type, val)}
                />
              ))}
            </div>

            {/* Modals */}
            {activeModal?.type === 'skills' && (
              <SkillsModal 
                isOpen={true}
                teamState={teams[activeModal.teamColor]}
                onClose={() => setActiveModal(null)}
                toggleSkill={(skillId) => handleToggleSkill(activeModal.teamColor, skillId)}
              />
            )}

            {activeModal?.type === 'questions' && (
              <QuestionsModal 
                isOpen={true}
                teamState={teams[activeModal.teamColor]}
                onClose={() => setActiveModal(null)}
                toggleQuestion={(qId) => handleToggleQuestion(activeModal.teamColor, qId)}
              />
            )}

            {/* Reward Popup */}
            {rewardData && (
                <RewardModal 
                    teamColor={rewardData.teamColor}
                    resources={rewardData.resources}
                    source={rewardData.source}
                    onClose={() => setRewardData(null)}
                />
            )}

          </div>
        )}
      </main>
    </div>
  );
};

export default App;

export type TeamColor = 'red' | 'green' | 'yellow' | 'orange';

export type Resource = 'kennis' | 'samenwerking' | 'tijd' | 'besluitkracht' | 'materiaal' | 'keuze';

export interface Skill {
  id: string;
  name: string;
  rewards: Resource[];
}

export interface Question {
  id: number;
  question: string;
  answer: string;
}

export interface DoorState {
  basic: number;
  min30: number;
  min60: number;
}

export interface TeamState {
  color: TeamColor;
  active: boolean;
  completedSkills: string[]; // List of Skill IDs
  answeredQuestions: number[]; // List of Question IDs
  incidentDone: boolean;
  routeLength: number;
  doors: DoorState;
}

export interface TeamConfig {
  id: TeamColor;
  name: string;
  hex: string;
  textColor: string;
}

import { Skill, Question, TeamConfig, Resource } from './types';
import { BookOpen, Users, Clock, Gavel, Package, Star } from 'lucide-react';

