import React from 'react';
import { TeamState, DoorState } from '../types';
import { TEAMS, DOOR_POINTS } from '../constants';
import { Trophy, Route, DoorOpen, AlertTriangle } from 'lucide-react';

interface Props {
  teams: TeamState[];
}

const calculateDoorPoints = (doors: DoorState) => {
  return (doors.basic * DOOR_POINTS.basic) + 
         (doors.min30 * DOOR_POINTS.min30) + 
         (doors.min60 * DOOR_POINTS.min60);
};

const Leaderboard: React.FC<Props> = ({ teams }) => {
  if (teams.length === 0) return null;

  const maxRoute = Math.max(...teams.map(t => t.routeLength));
  const maxDoorPoints = Math.max(...teams.map(t => calculateDoorPoints(t.doors)));

  const teamsWithScores = teams.map(team => {
    let score = 0;
    const doorPoints = calculateDoorPoints(team.doors);

    // Simplified Scoring Rules
    const hasLongestRoute = team.routeLength > 0 && team.routeLength === maxRoute; 
    const hasBestDoors = doorPoints > 0 && doorPoints === maxDoorPoints;           
    const incidentPoints = team.incidentCount * 2; 

    if (hasLongestRoute) score += 2;
    if (hasBestDoors) score += 2;
    score += incidentPoints;

    return {
      ...team,
      score,
      stats: {
        hasLongestRoute,
        hasBestDoors,
        incidentCount: team.incidentCount,
        incidentPoints,
        doorPoints
      }
    };
  });

  const highestScore = Math.max(...teamsWithScores.map(t => t.score));
  const leaders = teamsWithScores.filter(t => t.score === highestScore);

  return (
    <div className="mb-8">
      <div className="flex items-center gap-3 mb-4">
        <div className="p-2 bg-yellow-100 rounded-full text-yellow-600">
            <Trophy size={24} />
        </div>
        <h2 className="text-2xl font-bold text-slate-800">
            {leaders.length > 1 ? 'Huidige Koplopers' : 'Huidige Koploper'}
        </h2>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {leaders.map(team => {
          const config = TEAMS[team.color];
          return (
            <div 
              key={team.color}
              className="relative overflow-hidden bg-white rounded-2xl shadow-xl border-2 border-yellow-400 transform transition-all animate-in slide-in-from-bottom-4"
            >
                <div style={{ backgroundColor: config.hex }} className="h-24 relative overflow-hidden">
                    <div className="absolute inset-0 bg-black/10"></div>
                    <div className="absolute -bottom-6 -right-6 text-white/20">
                        <Trophy size={120} />
                    </div>
                    <div className="relative z-10 p-6 flex justify-between items-center">
                        <h3 className={`text-3xl font-black uppercase tracking-tight ${config.textColor}`}>
                            {config.name}
                        </h3>
                        <div className="flex flex-col items-center justify-center w-16 h-16 bg-white rounded-full shadow-lg">
                            <span className="text-2xl font-black text-slate-900">{team.score}</span>
                            <span className="text-[10px] font-bold text-slate-500 uppercase -mt-1">Punten</span>
                        </div>
                    </div>
                </div>

                <div className="p-4 space-y-3 bg-white">
                    <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">Puntenoverzicht</p>

                    <div className={`flex items-center justify-between p-2 rounded-lg ${team.stats.incidentCount > 0 ? 'bg-red-50 text-red-900' : 'bg-slate-50 text-slate-400 opacity-50'}`}>
                        <div className="flex items-center gap-2">
                            <AlertTriangle size={16} />
                            <span className="font-medium text-sm">Incidenten ({team.stats.incidentCount})</span>
                        </div>
                        <span className="font-bold">+{team.stats.incidentPoints}</span>
                    </div>

                    <div className={`flex items-center justify-between p-2 rounded-lg ${team.stats.hasLongestRoute ? 'bg-orange-50 text-orange-900' : 'bg-slate-50 text-slate-400 opacity-50'}`}>
                        <div className="flex items-center gap-2">
                            <Route size={16} />
                            <span className="font-medium text-sm">Langste Route Bonus</span>
                        </div>
                        <span className="font-bold">+2</span>
                    </div>

                    <div className={`flex items-center justify-between p-2 rounded-lg ${team.stats.hasBestDoors ? 'bg-purple-50 text-purple-900' : 'bg-slate-50 text-slate-400 opacity-50'}`}>
                        <div className="flex items-center gap-2">
                            <DoorOpen size={16} />
                            <span className="font-medium text-sm">Beste Deuren Bonus</span>
                        </div>
                        <span className="font-bold">+2</span>
                    </div>
                </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

