import React from 'react';
import { TEAMS, BUILDING_COSTS, RESOURCE_CONFIG } from '../constants';
import { TeamState, Resource } from '../types';
import { AlertTriangle, Route, DoorOpen, Plus, Minus, ShieldCheck } from 'lucide-react';

interface Props {
  teamState: TeamState;
  onAddIncident: () => void;
  onRemoveIncident: () => void;
  onUpdateCount: (field: 'routeLength' | 'doorCount' | 'extinguisherCount', val: number) => void;
}

const ResourceHex = ({ resource, amount }: { resource: Resource; amount: number }) => {
  const config = RESOURCE_CONFIG[resource];
  const Icon = config.icon;
  return (
    <div className="flex flex-col items-center gap-0.5">
      <div 
        className={`hexagon w-8 h-9 flex items-center justify-center text-white shadow-sm ${config.color}`}
        title={config.label}
      >
        <Icon size={14} />
      </div>
      <span className="text-[10px] font-black text-slate-600">x{amount}</span>
    </div>
  );
};

const CostRow = ({ costs }: { costs: Array<{ resource: Resource; amount: number }> }) => (
  <div className="flex gap-2 mt-1">
    {costs.map((c, i) => (
      <ResourceHex key={i} resource={c.resource} amount={c.amount} />
    ))}
  </div>
);

const TeamCard: React.FC<Props> = ({ 
  teamState, 
  onAddIncident,
  onRemoveIncident,
  onUpdateCount
}) => {
  const teamConfig = TEAMS[teamState.color];

  return (
    <div className="bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-200 flex flex-col h-full transform transition-all hover:shadow-2xl">
      {/* Header */}
      <div 
        className="p-6 relative overflow-hidden"
        style={{ backgroundColor: teamConfig.hex }}
      >
        <div className="relative z-10 flex justify-between items-start">
            <div>
                <h2 className={`text-3xl font-black tracking-tight ${teamConfig.textColor}`}>
                Team {teamConfig.name}
                </h2>
                <span className={`text-sm font-medium opacity-80 uppercase tracking-wider ${teamConfig.textColor}`}>
                BHV land
                </span>
            </div>
            {teamState.incidentCount > 0 && (
                <div className="bg-white/20 backdrop-blur-md px-3 py-1 rounded-full border border-white/30 text-white flex items-center gap-2">
                    <div className="w-2 h-2 rounded-full bg-red-400 animate-pulse"></div>
                    <span className="text-sm font-bold">{teamState.incidentCount} Incidenten</span>
                </div>
            )}
        </div>
        <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-white opacity-10 rounded-full blur-2xl"></div>
      </div>

      {/* Incident Actions */}
      <div className="p-6 space-y-4">
        <div className="p-4 rounded-xl border-2 border-red-200 bg-red-50">
            <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-3">
                    <div className="p-2 rounded-lg bg-red-200 text-red-700">
                        <AlertTriangle size={20} />
                    </div>
                    <div>
                        <p className="font-bold text-red-800">Incidenten</p>
                    </div>
                </div>
            </div>
            <div className="flex items-center justify-between bg-white rounded-lg p-1 border border-red-200">
                <button 
                    onClick={onRemoveIncident}
                    className="w-10 h-10 flex items-center justify-center rounded hover:bg-red-50 text-red-600 transition-colors"
                ><Minus size={20} /></button>
                <span className="font-mono font-black text-2xl text-red-800">{teamState.incidentCount}</span>
                <button 
                    onClick={onAddIncident}
                    className="w-10 h-10 flex items-center justify-center rounded bg-red-600 hover:bg-red-700 text-white transition-colors"
                >
                    <Plus size={24} />
                </button>
            </div>
        </div>
      </div>

      {/* Tracking (Purchases) */}
      <div className="bg-slate-50 border-t border-slate-200 flex-1">
        {/* Route */}
        <div className="p-4 border-b border-slate-200">
            <div className="flex justify-between items-start mb-2">
                <label className="text-[10px] font-bold uppercase text-slate-400 flex items-center gap-1 mt-1">
                    <Route size={10} /> Vluchtroute
                </label>
                <CostRow costs={BUILDING_COSTS.route} />
            </div>
            <div className="flex items-center justify-between bg-white rounded-lg p-1 border border-slate-200">
                <button 
                    onClick={() => onUpdateCount('routeLength', teamState.routeLength - 1)}
                    className="w-8 h-8 flex items-center justify-center rounded hover:bg-slate-100 text-slate-600 font-bold"
                >-</button>
                <span className="font-mono font-bold text-lg text-slate-800">{teamState.routeLength}</span>
                <button 
                    onClick={() => onUpdateCount('routeLength', teamState.routeLength + 1)}
                    className="w-8 h-8 flex items-center justify-center rounded hover:bg-slate-100 text-slate-600 font-bold"
                >+</button>
            </div>
        </div>

        {/* Door */}
        <div className="p-4 border-b border-slate-200">
            <div className="flex justify-between items-start mb-2">
                <label className="text-[10px] font-bold uppercase text-slate-400 flex items-center gap-1 mt-1">
                    <DoorOpen size={10} /> Deur
                </label>
                <CostRow costs={BUILDING_COSTS.door} />
            </div>
            <div className="flex items-center justify-between bg-white rounded-lg p-1 border border-slate-200">
                <button 
                    onClick={() => onUpdateCount('doorCount', teamState.doorCount - 1)}
                    className="w-8 h-8 flex items-center justify-center rounded hover:bg-slate-100 text-slate-600 font-bold"
                >-</button>
                <span className="font-mono font-bold text-lg text-slate-800">{teamState.doorCount}</span>
                <button 
                    onClick={() => onUpdateCount('doorCount', teamState.doorCount + 1)}
                    className="w-8 h-8 flex items-center justify-center rounded hover:bg-slate-100 text-slate-600 font-bold"
