import React, { useState } from 'react';
import { TeamState, TeamColor, Resource } from '../types';
import { TEAMS, CHALLENGE_INCIDENTS, RESOURCE_CONFIG } from '../constants';
import { X, Sword, Check, UserPlus, Trophy, AlertCircle } from 'lucide-react';

interface Props {
  challenger: TeamState;
  activeTeams: TeamState[];
  onClose: () => void;
  onComplete: (challengerCorrect: boolean, opponentCorrect: boolean, opponentColor: TeamColor) => void;
}

const ChallengeModal: React.FC<Props> = ({ challenger, activeTeams, onClose, onComplete }) => {
  const [step, setStep] = useState<'choose' | 'question' | 'result'>('choose');
  const [opponentColor, setOpponentColor] = useState<TeamColor | null>(null);
  const [challengerCorrect, setChallengerCorrect] = useState<boolean>(false);
  const [opponentCorrect, setOpponentCorrect] = useState<boolean>(false);

  const incident = CHALLENGE_INCIDENTS[Math.floor(Math.random() * CHALLENGE_INCIDENTS.length)];
  const challengerConfig = TEAMS[challenger.color];
  const opponents = activeTeams.filter(t => t.color !== challenger.color);

  const handleFinish = () => {
    if (opponentColor) {
      onComplete(challengerCorrect, opponentCorrect, opponentColor);
    }
  };

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl overflow-hidden transform animate-in zoom-in-95 duration-200">

        {/* Header */}
        <div className="bg-slate-900 p-6 flex justify-between items-center border-b border-white/10">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-500 rounded-lg text-white">
              <Sword size={24} />
            </div>
            <div>
              <h2 className="text-xl font-black text-white uppercase tracking-tighter">Team Uitdaging</h2>
              <p className="text-slate-400 text-xs font-bold uppercase">Duel om grondstoffen</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-white/10 text-slate-400 transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="p-8">
          {step === 'choose' && (
            <div className="space-y-6">
              <div className="text-center">
                <h3 className="text-2xl font-bold text-slate-800">Wie daag je uit?</h3>
                <p className="text-slate-500">Kies een team om de strijd mee aan te gaan.</p>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {opponents.length > 0 ? opponents.map(team => (
                  <button
                    key={team.color}
                    onClick={() => {
                      setOpponentColor(team.color);
                      setStep('question');
                    }}
                    className="flex items-center gap-4 p-5 rounded-2xl border-2 border-slate-100 hover:border-indigo-500 hover:bg-indigo-50 transition-all group text-left"
                  >
                    <div className="w-12 h-12 rounded-full shadow-inner flex items-center justify-center" style={{ backgroundColor: TEAMS[team.color].hex }}>
                       <UserPlus size={24} className={TEAMS[team.color].textColor} />
                    </div>
                    <div>
                      <span className="block text-lg font-black text-slate-800 uppercase tracking-tight">Team {TEAMS[team.color].name}</span>
                      <span className="text-xs font-bold text-slate-400 uppercase">Uitdagen</span>
                    </div>
                  </button>
                )) : (
                  <div className="col-span-full p-8 text-center bg-slate-100 rounded-2xl text-slate-400 italic">
                    Geen andere actieve teams beschikbaar...
                  </div>
                )}
              </div>
            </div>
          )}

          {step === 'question' && opponentColor && (
            <div className="space-y-6">
              <div className="p-5 bg-amber-50 rounded-2xl border-2 border-amber-100">
                <div className="flex items-center gap-3 mb-2">
                  <AlertCircle className="text-amber-600" size={20} />
                  <h4 className="font-black text-amber-900 uppercase text-sm">Incident Scenario</h4>
                </div>
                <h3 className="text-xl font-bold text-slate-800 mb-1">{incident.title}</h3>
                <p className="text-slate-700 leading-relaxed italic">"{incident.scenario}"</p>
              </div>

              <div className="space-y-4">
                <h4 className="text-center font-bold text-slate-800 text-lg">{incident.question}</h4>
                <div className="grid grid-cols-2 gap-3">
                  {incident.options.map((opt, i) => (
                    <div key={i} className={`p-3 rounded-xl border-2 text-center text-sm font-bold ${opt === incident.correctAnswer ? 'border-green-500 bg-green-50 text-green-800' : 'border-slate-100 bg-slate-50 text-slate-400'}`}>
                      {opt}
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6 pt-4 border-t border-slate-100">
                {/* Challenger Toggle */}
                <div className="text-center space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400">Uitdager</p>
                   <div className="text-lg font-black uppercase" style={{ color: challengerConfig.hex }}>{challengerConfig.name}</div>
                   <button 
                    onClick={() => setChallengerCorrect(!challengerCorrect)}
                    className={`w-full py-3 rounded-xl border-2 flex items-center justify-center gap-2 transition-all ${challengerCorrect ? 'bg-green-600 border-green-600 text-white shadow-lg' : 'border-slate-200 text-slate-400'}`}
                   >
                     {challengerCorrect ? <Check size={20} /> : null}
                     {challengerCorrect ? 'Correct' : 'Markeer Correct'}
                   </button>
                </div>

                {/* Opponent Toggle */}
                <div className="text-center space-y-3">
                   <p className="text-[10px] font-black uppercase text-slate-400">Uitgedaagde</p>
                   <div className="text-lg font-black uppercase" style={{ color: TEAMS[opponentColor].hex }}>{TEAMS[opponentColor].name}</div>
                   <button 
                    onClick={() => setOpponentCorrect(!opponentCorrect)}
                    className={`w-full py-3 rounded-xl border-2 flex items-center justify-center gap-2 transition-all ${opponentCorrect ? 'bg-green-600 border-green-600 text-white shadow-lg' : 'border-slate-200 text-slate-400'}`}
                   >
                     {opponentCorrect ? <Check size={20} /> : null}
                     {opponentCorrect ? 'Correct' : 'Markeer Correct'}
                   </button>
                </div>
              </div>

              <button
                onClick={() => setStep('result')}
                className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl"
              >
                Volgende: Resultaat
              </button>
            </div>
          )}

          {step === 'result' && opponentColor && (
            <div className="space-y-8 py-4">
              <div className="text-center">
                <div className="inline-block p-4 bg-yellow-100 rounded-full text-yellow-600 mb-4 animate-bounce">
                  <Trophy size={48} />
                </div>
                <h3 className="text-3xl font-black text-slate-800 uppercase">Strijd Voltooid!</h3>
                <p className="text-slate-500">De instructeur heeft de antwoorden beoordeeld.</p>
              </div>

              <div className="grid gap-4">
                {/* Challenger Reward Display */}
                <div className={`p-4 rounded-2xl border-2 flex items-center justify-between ${challengerCorrect ? 'border-green-200 bg-green-50' : 'border-slate-100 bg-slate-50 opacity-60'}`}>
                  <div className="flex items-center gap-4">
                     <div className="w-10 h-10 rounded-full flex items-center justify-center text-white font-bold" style={{ backgroundColor: challengerConfig.hex }}>{challengerConfig.name[0]}</div>
                     <div>
                       <span className="block font-black text-slate-800">Team {challengerConfig.name}</span>
                       <span className="text-xs text-slate-500">{challengerCorrect ? 'Correct beantwoord' : 'Fout beantwoord'}</span>
                     </div>
                  </div>
                  {challengerCorrect && (
                    <div className="flex items-center gap-2 bg-yellow-400 px-3 py-1 rounded-full text-xs font-black text-yellow-900">
                      <Star size={12} fill="currentColor" />
                      1x Keuze Kaart
                    </div>
                  )}
                </div>

                {/* Opponent Reward Display */}
                <div className={`p-4 rounded-2xl border-2 flex items-center justify-between ${opponentCorrect ? 'border-green-200 bg-green-50' : 'border-slate-100 bg-slate-50 opacity-60'}`}>
                  <div className="flex items-center gap-4">
                     <div className="w-10 h-10 rounded-full flex items-center justify-center text-white font-bold" style={{ backgroundColor: TEAMS[opponentColor].hex }}>{TEAMS[opponentColor].name[0]}</div>
                     <div>
                       <span className="block font-black text-slate-800">Team {TEAMS[opponentColor].name}</span>
                       <span className="text-xs text-slate-500">{opponentCorrect ? 'Correct beantwoord' : 'Fout beantwoord'}</span>
                     </div>
                  </div>
                  {opponentCorrect && (
                    <div className="flex items-center gap-2 bg-yellow-400 px-3 py-1 rounded-full text-xs font-black text-yellow-900">
                      <Star size={12} fill="currentColor" />
                      2x Keuze Kaart
                    </div>
                  )}
                </div>
              </div>

              <button
                onClick={handleFinish}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase hover:bg-indigo-700 shadow-xl transition-all"
              >
                Grondstoffen Toekennen
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default ChallengeModal;

import React, { useState } from 'react';
import { TEAMS, INCIDENT_REWARDS } from './constants';
import { TeamState, TeamColor, Resource } from './types';
import TeamCard from './components/TeamCard';
import RewardModal from './components/RewardModal';
import ChallengeModal from './components/ChallengeModal';
import Leaderboard from './components/Leaderboard';
import { Users, LayoutDashboard, Crown } from 'lucide-react';

const initialTeamState = (color: TeamColor): TeamState => ({
  color,
  active: false,
  incidentCount: 0,
  routeLength: 0,
  doorCount: 0,
  extinguisherCount: 0,
  completedSkills: [],
  answeredQuestions: []
});

const App: React.FC = () => {
  const [view, setView] = useState<'setup' | 'dashboard'>('setup');

  const [teams, setTeams] = useState<Record<TeamColor, TeamState>>({
    red: initialTeamState('red'),
    green: initialTeamState('green'),
    yellow: initialTeamState('yellow'),
    orange: initialTeamState('orange'),
  });

  // Modal States
  const [rewardData, setRewardData] = useState<{ 
    teamColor: TeamColor; 
    resources: Resource[];
    source: string;
  } | null>(null);

  const [challengeChallenger, setChallengeChallenger] = useState<TeamState | null>(null);

  const toggleTeamActive = (color: TeamColor) => {
    setTeams(prev => ({
      ...prev,
      [color]: { ...prev[color], active: !prev[color].active }
    }));
  };

  const handleAddIncident = (teamColor: TeamColor) => {
    setTeams(prev => {
        setRewardData({
            teamColor,
            resources: INCIDENT_REWARDS,
            source: 'Incident opgelost'
        });

        return {
            ...prev,
            [teamColor]: { 
                ...prev[teamColor], 
                incidentCount: prev[teamColor].incidentCount + 1 
            }
        };
    });
  };

  const handleRemoveIncident = (teamColor: TeamColor) => {
    setTeams(prev => ({
        ...prev,
        [teamColor]: { 
            ...prev[teamColor], 
            incidentCount: Math.max(0, prev[teamColor].incidentCount - 1) 
        }
    }));
  };

  const handleChallengeComplete = (challengerCorrect: boolean, opponentCorrect: boolean, opponentColor: TeamColor) => {
    if (!challengeChallenger) return;

    const challengerColor = challengeChallenger.color;

    setTeams(prev => {
      const next = { ...prev };

      // Update incident counts for both
      next[challengerColor] = { ...next[challengerColor], incidentCount: next[challengerColor].incidentCount + 1 };
      next[opponentColor] = { ...next[opponentColor], incidentCount: next[opponentColor].incidentCount + 1 };

      return next;
    });

    // Award rewards via modal (sequential handling or just summary)
    // For simplicity, if correct, we show the summary of Choice rewards.
    // In a real scenario, we might want multiple reward modals, 
    // but here we can just close the challenge and assume the instructor handles the physical cards.
    setChallengeChallenger(null);
  };

  const handleUpdateCount = (teamColor: TeamColor, field: 'routeLength' | 'doorCount' | 'extinguisherCount', val: number) => {
    setTeams(prev => ({
      ...prev,
      [teamColor]: { ...prev[teamColor], [field]: Math.max(0, val) }
    }));
  };

  const activeTeamsList = (Object.values(teams) as TeamState[]).filter(t => t.active);
  const hasActiveTeams = activeTeamsList.length > 0;

  return (
    <div className="min-h-screen bg-slate-100 font-sans text-slate-900">
      <nav className="bg-white border-b border-slate-200 shadow-sm sticky top-0 z-30">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="bg-indigo-600 p-2 rounded-lg text-white">
                <Crown size={20} />
             </div>
             <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-violet-600">
               Instructeursdashboard BHV land
             </h1>
          </div>
          <div className="flex items-center gap-4">
            {view === 'dashboard' && (
              <button 
                onClick={() => setView('setup')}
                className="text-sm font-medium text-slate-500 hover:text-slate-800 transition-colors"
              >
                Teamconfiguratie
              </button>
            )}
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {view === 'setup' && (
          <div className="max-w-2xl mx-auto">
            <div className="text-center mb-10">
              <h2 className="text-3xl font-bold text-slate-800 mb-3">Welke teams spelen mee?</h2>
              <p className="text-slate-500">Selecteer de groepen die vandaag meedoen aan de training.</p>
            </div>
            <div className="grid gap-4">
              {(Object.keys(TEAMS) as TeamColor[]).map((color) => {
                const config = TEAMS[color];
                const isActive = teams[color].active;
                return (
                  <button
                    key={color}
                    onClick={() => toggleTeamActive(color)}
                    className={`flex items-center justify-between p-6 rounded-xl border-2 transition-all duration-300 shadow-sm hover:shadow-md ${
                      isActive 
                        ? 'border-indigo-600 bg-white scale-[1.02]' 
                        : 'border-transparent bg-slate-200 opacity-60 hover:opacity-100'
                    }`}
                  >
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-full shadow-inner flex items-center justify-center text-white font-bold`} style={{ backgroundColor: config.hex }}>
                         {isActive && <Users size={20} className={config.textColor} />}
                      </div>
                      <span className="text-xl font-bold text-slate-800">{config.name}</span>
                    </div>
                    <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center ${isActive ? 'bg-indigo-600 border-indigo-600' : 'border-slate-400'}`}>
                      {isActive && <Users size={16} className="text-white" />}
                    </div>
                  </button>
                );
              })}
            </div>
            <button
              onClick={() => setView('dashboard')}
              disabled={!hasActiveTeams}
              className={`w-full mt-8 py-4 rounded-xl font-bold text-lg shadow-lg flex items-center justify-center gap-2 transition-all ${
                hasActiveTeams 
                  ? 'bg-indigo-600 text-white hover:bg-indigo-700 translate-y-0' 
                  : 'bg-slate-300 text-slate-500 cursor-not-allowed'
              }`}
            >
              <LayoutDashboard size={24} />
              Dashboard Openen
            </button>
          </div>
        )}

        {view === 'dashboard' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {hasActiveTeams && (
                <Leaderboard teams={activeTeamsList} />
            )}
            <div className={`grid gap-6 ${activeTeamsList.length === 1 ? 'max-w-md mx-auto' : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-4'}`}>
              {activeTeamsList.map(team => (
                <TeamCard 
                  key={team.color}
                  teamState={team}
                  onAddIncident={() => handleAddIncident(team.color)}
                  onRemoveIncident={() => handleRemoveIncident(team.color)}
                  onStartChallenge={() => setChallengeChallenger(team)}
                  onUpdateCount={(field, val) => handleUpdateCount(team.color, field, val)}
                />
              ))}
            </div>

            {rewardData && (
                <RewardModal 
                    teamColor={rewardData.teamColor}
                    resources={rewardData.resources}
                    source={rewardData.source}
                    onClose={() => setRewardData(null)}
                />
            )}

            {challengeChallenger && (
              <ChallengeModal 
                challenger={challengeChallenger}
                activeTeams={activeTeamsList}
                onClose={() => setChallengeChallenger(null)}
                onComplete={handleChallengeComplete}
              />
            )}
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

