                    </div>
                  )}
                </div>

                {/* Opponent Reward Display */}
                <div className={`p-4 rounded-2xl border-2 flex items-center justify-between ${opponentCorrect ? 'border-green-200 bg-green-50' : 'border-slate-100 bg-slate-50 opacity-60'}`}>
