interface Props {
  teams: TeamState[];
}

const Leaderboard: React.FC<Props> = ({ teams }) => {
  if (teams.length === 0) return null;

  // Bepaal de maxima voor de bonussen
  const maxRoute = Math.max(...teams.map(t => t.routeLength));
  const maxDoors = Math.max(...teams.map(t => t.doorCount));
  const maxExtinguishers = Math.max(...teams.map(t => t.extinguisherCount));

  const teamsWithScores = teams.map(team => {
    // Basis Punten
    const doorPoints = team.doorCount * 1;
    const extinguisherPoints = team.extinguisherCount * 3; // 3 punten per individuele blusser

    // Bonus Punten (Titels)
    // Alleen toekennen als het aantal groter dan 0 is om '0-score' bonussen te voorkomen
    const hasLongestRoute = team.routeLength > 0 && team.routeLength === maxRoute; 
    const hasMostDoors = team.doorCount > 0 && team.doorCount === maxDoors;
    const hasMostExtinguishers = team.extinguisherCount > 0 && team.extinguisherCount === maxExtinguishers;

    let totalScore = doorPoints + extinguisherPoints;
    if (hasLongestRoute) totalScore += 2;      // Langste vluchtroute = 2pt
    if (hasMostDoors) totalScore += 2;         // Meeste deuren = 2pt
    if (hasMostExtinguishers) totalScore += 3; // Meeste blussers = 3pt

    return {
      ...team,
      score: totalScore,
      stats: {
        doorCount: team.doorCount,
        doorPoints,
        extinguisherCount: team.extinguisherCount,
        extinguisherPoints,
        hasLongestRoute,
        hasMostDoors,
        hasMostExtinguishers
      }
    };
  }).sort((a, b) => b.score - a.score);

  const highestScore = teamsWithScores[0].score;

  return (
    <div className="mb-12">
