                <Route size={12} /> Langste Route (2pt)
            </div>
            <div className="px-3 py-1.5 bg-blue-100 text-blue-700 rounded-full text-[10px] font-black uppercase border border-blue-200 flex items-center gap-1.5">
                <DoorOpen size={12} /> Meeste Deuren (2pt)
