            <div className="px-3 py-1.5 bg-green-100 text-green-700 rounded-full text-[10px] font-black uppercase border border-green-200 flex items-center gap-1.5">
                <ShieldCheck size={12} /> Meeste Blussers (3pt)
            </div>
