const initialTeamState = (color: TeamColor): TeamState => ({
  color,
  active: false,
  incidentCount: 0,
  routeLength: 0,
  doorCount: 0,
  extinguisherCount: 0,
  completedSkills: [],
  answeredQuestions: []
});

